# Get customer profile and order history
customer = tool('get_customer', customer_id='CUST-2244')
order_history = tool('get_order_history', customer_id='CUST-2244')

# Find the returned order (most recent one with "returned" status)
returned_order = None
for order in order_history['orders']:
    if order['status'].lower() == 'returned':
        returned_order = order
        break

# Get details of the returned order
if returned_order:
    order_details = tool('lookup_order', order_id=returned_order['id'])
else:
    order_details = None

{
    'customer': customer,
    'order_history': order_history,
    'returned_order': returned_order,
    'order_details': order_details
}

# Orders from CUST-8842
orders = [
    {"id": "ORD-7291", "date": "2026-02-15", "total": 129.97, "status": "shipped"},
    {"id": "ORD-7104", "date": "2026-01-28", "total": 64.5, "status": "delivered"},
    {"id": "ORD-6980", "date": "2026-01-10", "total": 219, "status": "delivered"},
    {"id": "ORD-6755", "date": "2025-12-05", "total": 42, "status": "returned"}
]

# Filter for orders over $50 with status 'shipped'
eligible_orders = [o for o in orders if o['total'] > 50 and o['status'] == 'shipped']

# Check days since for each eligible order
orders_to_process = []
for order in eligible_orders:
    days_result = tool('days_since', date=order['date'])
    days_passed = days_result['days']
    orders_to_process.append({
        'order_id': order['id'],
        'date': order['date'],
        'total': order['total'],
        'days_passed': days_passed,
        'needs_case': days_passed > 14
    })

# Create support cases for orders over 14 days
cases_created = []
for order_info in orders_to_process:
    if order_info['needs_case']:
        case_result = tool('create_case',
            customer_id='CUST-8842',
            order_id=order_info['order_id'],
            category='complaint',
            priority='medium',
            summary=f"Order {order_info['order_id']} has been in 'shipped' status for {order_info['days_passed']} days (over 14 days threshold)"
        )
        cases_created.append({
            'order_id': order_info['order_id'],
            'case_id': case_result['case_id'],
            'days_passed': order_info['days_passed']
        })

{
    'eligible_orders_checked': orders_to_process,
    'cases_created': cases_created,
    'summary': {
        'total_orders': len(orders),
        'eligible_orders': len(eligible_orders),
        'cases_opened': len(cases_created)
    }
}

# Comprehensive audit for all 3 customers
customer_ids = ['CUST-8842', 'CUST-2244', 'CUST-5501']

# Step 1: Get all customer profiles and order histories
customer_data = {}
for cust_id in customer_ids:
    profile = tool('get_customer', customer_id=cust_id)
    order_history = tool('get_order_history', customer_id=cust_id)
    customer_data[cust_id] = {
        'profile': profile,
        'order_history': order_history
    }

# Step 2: Collect all non-returned orders and their details
all_skus = []
order_details_map = {}

for cust_id in customer_ids:
    orders = customer_data[cust_id]['order_history']['orders']
    non_returned_orders = [o for o in orders if o['status'] != 'returned']

    for order in non_returned_orders:
        order_detail = tool('lookup_order', order_id=order['id'])
        order_details_map[order['id']] = order_detail

        # Collect all SKUs from this order
        for item in order_detail['items']:
            all_skus.append(item['sku'])

# Step 3: Check inventory for all SKUs
unique_skus = []
seen = set()
for sku in all_skus:
    if sku not in seen:
        unique_skus.append(sku)
        seen.add(sku)

inventory_result = tool('check_inventory', sku_list=unique_skus)
inventory_map = {}
for item in inventory_result['items']:
    inventory_map[item['sku']] = item

# Step 4: Build audit results per customer
audit_results = {}

for cust_id in customer_ids:
    profile = customer_data[cust_id]['profile']
    orders = customer_data[cust_id]['order_history']['orders']
    non_returned_orders = [o for o in orders if o['status'] != 'returned']

    out_of_stock_items = []
    order_summaries = []

    for order in non_returned_orders:
        order_detail = order_details_map[order['id']]
        order_items = []

        for item in order_detail['items']:
            sku = item['sku']
            inv = inventory_map.get(sku, {})
            available = inv.get('available', 0)

            item_info = {
                'name': item['name'],
                'sku': sku,
                'price': item['price'],
                'in_stock': available > 0,
                'available_qty': available
            }
            order_items.append(item_info)

            if available == 0:
                out_of_stock_items.append({
                    'order_id': order['id'],
                    'item_name': item['name'],
                    'sku': sku,
                    'price': item['price']
                })

        order_summaries.append({
            'order_id': order['id'],
            'date': order['date'],
            'status': order['status'],
            'total': order['total'],
            'items': order_items
        })

    audit_results[cust_id] = {
        'customer_name': profile['name'],
        'email': profile['email'],
        'tier': profile['tier'],
        'loyalty_points': profile['loyalty_points'],
        'account_status': profile['account_status'],
        'member_since': profile['member_since'],
        'total_non_returned_orders': len(non_returned_orders),
        'order_summaries': order_summaries,
        'out_of_stock_items': out_of_stock_items,
        'out_of_stock_count': len(out_of_stock_items)
    }

# Step 5: Send summary emails to each customer
email_results = []

for cust_id in customer_ids:
    audit = audit_results[cust_id]

    # Build email body
    email_body = f"""Dear {audit['customer_name']},

This is your account audit summary as of 2026-03-10.

ACCOUNT INFORMATION:
- Membership Tier: {audit['tier']}
- Loyalty Points: {audit['loyalty_points']}
- Account Status: {audit['account_status']}
- Member Since: {audit['member_since']}

ORDER AUDIT SUMMARY:
- Total Non-Returned Orders Reviewed: {audit['total_non_returned_orders']}

"""

    if audit['order_summaries']:
        email_body += "ORDER DETAILS:\n"
        for order in audit['order_summaries']:
            email_body += f"\nOrder {order['order_id']} ({order['date']}) - Status: {order['status']} - Total: ${order['total']}\n"
            for item in order['items']:
                stock_status = "✓ In Stock" if item['in_stock'] else "✗ OUT OF STOCK"
                email_body += f"  - {item['name']} (SKU: {item['sku']}) - ${item['price']} - {stock_status} (Qty: {item['available_qty']})\n"

    if audit['out_of_stock_items']:
        email_body += f"\n⚠️ INVENTORY ALERT:\n"
        email_body += f"Found {audit['out_of_stock_count']} out-of-stock item(s) in your orders:\n"
        for item in audit['out_of_stock_items']:
            email_body += f"  - {item['item_name']} (SKU: {item['sku']}) in Order {item['order_id']} - ${item['price']}\n"
    else:
        email_body += "\n✓ All items in your orders are currently in stock.\n"

    email_body += "\nBest regards,\nAudit Team"

    # Send email
    email_result = tool('send_notification',
        channel='email',
        recipient=audit['email'],
        subject=f'Account Audit Summary - {cust_id}',
        body=email_body
    )

    email_results.append({
        'customer_id': cust_id,
        'email': audit['email'],
        'notification_id': email_result['notification_id'],
        'sent_at': email_result['sent_at'],
        'status': email_result['status']
    })

# Return comprehensive audit summary
{
    'audit_date': '2026-03-10',
    'customers_audited': len(customer_ids),
    'total_orders_reviewed': sum(len(audit['order_summaries']) for audit in audit_results.values()),
    'total_out_of_stock_items': sum(audit['out_of_stock_count'] for audit in audit_results.values()),
    'audit_results': audit_results,
    'emails_sent': email_results
}
